export const SETTINGS_SECTIONS = Object.freeze([
  {
    id: "shopping",
    label: "Shopping",
    href: "#shopping",
  },
]);

export const SHOPPING_SETUP_PLACEHOLDER =
  "Shopping preferences are in setup. Profile controls will appear here in a later milestone.";

export function renderSettingsShoppingPane({ profile } = {}) {
  const profileState = profile ? "Profile data loaded." : "No shopping profile data yet.";

  return [
    '<section id="shopping" class="settings-pane" aria-labelledby="shopping-heading">',
    '  <p class="settings-kicker">Settings</p>',
    '  <h1 id="shopping-heading">Shopping</h1>',
    `  <p class="settings-placeholder">${escapeHtml(SHOPPING_SETUP_PLACEHOLDER)}</p>`,
    `  <p class="settings-status">${escapeHtml(profileState)}</p>`,
    "</section>",
  ].join("\n");
}

export function renderSettingsApp({ activeSection = "shopping", profile } = {}) {
  const active = SETTINGS_SECTIONS.some((section) => section.id === activeSection)
    ? activeSection
    : "shopping";

  return [
    '<main class="settings-shell" aria-label="Settings">',
    '  <aside class="settings-sidebar" aria-label="Settings sections">',
    "    <h2>Settings</h2>",
    '    <nav aria-label="Settings navigation">',
    ...SETTINGS_SECTIONS.map((section) => renderSettingsNavLink(section, active)),
    "    </nav>",
    "  </aside>",
    `  ${renderSettingsShoppingPane({ profile }).replaceAll("\n", "\n  ")}`,
    "</main>",
  ].join("\n");
}

function renderSettingsNavLink(section, activeSection) {
  const current = section.id === activeSection ? ' aria-current="page"' : "";
  return `      <a href="${section.href}"${current}>${escapeHtml(section.label)}</a>`;
}

function escapeHtml(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

import test from "node:test";
import assert from "node:assert/strict";

import {
  SHOPPING_SETUP_PLACEHOLDER,
  renderSettingsApp,
  renderSettingsShoppingPane,
} from "../src/settings-shopping-pane.mjs";

test("renders a navigable Settings Shopping section", () => {
  const html = renderSettingsApp();

  assert.match(html, /aria-label="Settings"/);
  assert.match(html, /href="#shopping"/);
  assert.match(html, /aria-current="page">Shopping<\/a>/);
  assert.match(html, /<section id="shopping"/);
  assert.match(html, new RegExp(SHOPPING_SETUP_PLACEHOLDER));
});

test("renders the Shopping pane without profile data", () => {
  assert.doesNotThrow(() => renderSettingsShoppingPane());

  const html = renderSettingsShoppingPane();

  assert.match(html, /Shopping/);
  assert.match(html, /No shopping profile data yet\./);
});

test("accepts present profile data without changing the empty setup shell", () => {
  const html = renderSettingsShoppingPane({
    profile: {
      country: "LV",
      currency: "EUR",
    },
  });

  assert.match(html, /Profile data loaded\./);
  assert.match(html, new RegExp(SHOPPING_SETUP_PLACEHOLDER));
});

import { appendFile, mkdir, readFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";

export const SHOPPING_AUDIT_LOG_SCHEMA_VERSION = 1;
export const DEFAULT_SHOPPING_AUDIT_LOG_PATH = "data/shopping-audit-log.jsonl";
export const SHOPPING_AUDIT_ACTION_TYPES = Object.freeze([
  "search",
  "page_read",
  "cart_add",
  "cart_peek",
]);
export const SHOPPING_AUDIT_STATUSES = Object.freeze(["started", "succeeded", "failed"]);

let auditWriteQueue = Promise.resolve();

export function createShoppingAuditEntry(entry, now = new Date()) {
  if (!entry || typeof entry !== "object" || Array.isArray(entry)) {
    throw new TypeError("Shopping audit entry must be an object.");
  }

  const normalized = {
    schemaVersion: SHOPPING_AUDIT_LOG_SCHEMA_VERSION,
    actionType: normalizeEnum(entry.actionType, "actionType", SHOPPING_AUDIT_ACTION_TYPES),
    retailer: normalizeString(entry.retailer, "retailer"),
    timestamp: normalizeTimestamp(entry.timestamp ?? now),
    status: normalizeEnum(entry.status, "status", SHOPPING_AUDIT_STATUSES),
  };

  if (entry.screenshotPath !== undefined) {
    normalized.screenshotPath = normalizeString(entry.screenshotPath, "screenshotPath");
  }

  return normalized;
}

export function appendShoppingAuditEntry(
  entry,
  filePath = DEFAULT_SHOPPING_AUDIT_LOG_PATH,
  options = {},
) {
  const normalized = createShoppingAuditEntry(entry, options.now);
  const target = resolve(filePath);

  auditWriteQueue = auditWriteQueue
    .catch(() => undefined)
    .then(async () => {
      await mkdir(dirname(target), { recursive: true });
      await appendFile(target, `${JSON.stringify(normalized)}\n`, "utf8");
    })
    .catch((err) => {
      if (typeof options.onError === "function") {
        options.onError(err);
      }
    });

  return normalized;
}

export async function flushShoppingAuditLog() {
  await auditWriteQueue;
}

export async function readShoppingAuditLog(filePath = DEFAULT_SHOPPING_AUDIT_LOG_PATH) {
  try {
    const raw = await readFile(resolve(filePath), "utf8");
    return raw
      .split("\n")
      .filter(Boolean)
      .map((line) => createShoppingAuditEntry(JSON.parse(line)));
  } catch (err) {
    if (err.code === "ENOENT") {
      return [];
    }
    throw err;
  }
}

function normalizeEnum(value, field, allowedValues) {
  if (!allowedValues.includes(value)) {
    throw new TypeError(`${field} must be one of: ${allowedValues.join(", ")}.`);
  }
  return value;
}

function normalizeString(value, field) {
  if (typeof value !== "string" || !value.trim()) {
    throw new TypeError(`${field} must be a non-empty string.`);
  }
  return value.trim();
}

function normalizeTimestamp(value) {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) {
    throw new TypeError("timestamp must be a valid date or ISO timestamp.");
  }
  return date.toISOString();
}

